{-# LANGUAGE OverloadedStrings #-}
{-# LANGUAGE OverloadedRecordDot #-}

module Bitcoin.TransactionSpec (spec) where

import qualified Test.Hspec as H
import Data.Serialize

import Utils.Hex
import Utils.Hash
import Utils.Print.PrintTransaction
import Bitcoin.Transaction


spec :: H.Spec
spec = do
    H.describe "Parse Trasaction" $ do

        let sampleTx1 = hexToBytes ""
        let sampleTx2 = hexToBytes ""
        H.it "get test" $ do
            let Right tx1 = runGet (get :: Get Tx) sampleTx1
                Right tx2 = runGet (get :: Get Tx) sampleTx2
            printTx tx1
            print $ "tx1 -> hashed -> reversed: " ++ show (txId tx1)
            print $ "tx2 -> hashed -> reversed: " ++ show (txId tx2)

